import{_ as e,o as a,c as r,a2 as n}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"Features","description":"Review Sovereign capabilities with clear availability status.","frontmatter":{"title":"Features","description":"Review Sovereign capabilities with clear availability status.","aside":false},"headers":[],"relativePath":"product/features.md","filePath":"product/features.md"}'),i={name:"product/features.md"};function s(o,t,d,l,p,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="features-and-status" tabindex="-1">Features and status <a class="header-anchor" href="#features-and-status" aria-label="Permalink to &quot;Features and status&quot;">​</a></h1><p>Sovereign separates shipped behavior from work that is still underway. Status describes the project, not whether a particular operator has enabled a feature on their instance.</p><h2 id="available" tabindex="-1">Available <a class="header-anchor" href="#available" aria-label="Permalink to &quot;Available&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>What it provides</th><th>Learn more</th></tr></thead><tbody><tr><td>Workspace shell and Launcher</td><td>One responsive environment for opening installed apps.</td><td><a href="/plugins/launcher.html">Launcher</a></td></tr><tr><td>Accounts and sessions</td><td>Email/password sign-in, account settings, session handling, and recovery flows.</td><td><a href="/plugins/account.html">Account</a></td></tr><tr><td>Passkeys and TOTP</td><td>Stronger account authentication when configured by the instance.</td><td><a href="/security.html">Security</a></td></tr><tr><td>Multi-user administration</td><td>Operator controls for users, roles, apps, and instance settings.</td><td><a href="/plugins/console.html">Console</a></td></tr><tr><td>Installable PWA</td><td>Home Screen, app launcher, or desktop installation with a standalone window.</td><td><a href="/docs/pwa.html">Install as an app</a></td></tr><tr><td>Push notifications</td><td>Optional per-device background notifications when configured by the operator.</td><td><a href="/docs/pwa.html#enable-push-notifications">Notification setup</a></td></tr><tr><td>Plugin SDK boundary</td><td>A supported contract between apps and the runtime.</td><td><a href="/plugin-development.html">Build plugins</a></td></tr><tr><td>App-scoped databases</td><td>User-scoped plugin data with supported database helpers.</td><td><a href="/plugin-database.html">Plugin database</a></td></tr><tr><td>Shared design system</td><td>Tokens and React components for a consistent workspace UI.</td><td><a href="/design-system.html">Design system</a></td></tr><tr><td>Data export and account controls</td><td>User-facing access to profile, security, preferences, and portability flows.</td><td><a href="/plugins/account.html">Account</a></td></tr></tbody></table><h2 id="in-development" tabindex="-1">In development <a class="header-anchor" href="#in-development" aria-label="Permalink to &quot;In development&quot;">​</a></h2><p>These capabilities have active designs or implementations, but public behavior may still change:</p><ul><li>Broader plugin storage and portability contracts.</li><li>Background jobs, events, external connections, and richer plugin tools.</li><li>Improved operator backup and recovery workflows.</li><li>Expanded device shells and app experiences.</li></ul><p>Review the <a href="/product-roadmap.html">public product roadmap</a> for outcome-level direction and the <a href="/rfcs/README.html">RFC index</a> for technical proposals.</p><h2 id="planned-or-exploring" tabindex="-1">Planned or exploring <a class="header-anchor" href="#planned-or-exploring" aria-label="Permalink to &quot;Planned or exploring&quot;">​</a></h2><ul><li>Client-side encryption foundations for apps that handle sensitive content.</li><li>Peer-to-peer chat with a separate identity and transport model.</li><li>Assistant and orchestration experiences built on explicit platform contracts.</li></ul><p>These are not available features. Draft RFCs describe possible designs, not a delivery guarantee.</p>',11)])])}const f=e(i,[["render",s]]);export{u as __pageData,f as default};
